const PER_PAGE=6;function renderStars(rating){const full=Math.floor(rating);const half=rating-full >=0.5;let s='';for(let i=0;i < full;i++)s+='<i class="bi bi-star-fill" style="color:var(--accent-gold);"></i>';if(half)s+='<i class="bi bi-star-half" style="color:var(--accent-gold);"></i>';for(let i=0;i < 5-full-(half ? 1:0);i++)s+='<i class="bi bi-star" style="color:var(--border-color);"></i>';return s;}function productCardHTML(p){return ` <div class="product-card"> <div class="product-img-wrap"> <a href="product-detail.html?id=${escapeHtml(p.id)}"> <img loading="lazy" src="${escapeHtml(p.image)}" alt="${escapeHtml(p.name)}" class="product-img"> </a> ${p.badge ? `<span class="product-badge">${escapeHtml(p.badge)}</span>`:''}<button class="wishlist-btn" data-id="${escapeHtml(p.id)}" aria-label="Add to wishlist" style="position:absolute;top:0.75rem;right:0.75rem;background:rgba(255,255,255,0.9);border:none;border-radius:50%;width:32px;height:32px;cursor:pointer;font-size:1rem;display:flex;align-items:center;justify-content:center;"> <i class="bi bi-heart" style="color:var(--primary-color);"></i> </button> </div> <div class="product-info"> <a href="product-detail.html?id=${escapeHtml(p.id)}" style="text-decoration:none;color:inherit;"> <h3 class="product-name">${escapeHtml(p.name)}</h3> </a> <p class="product-seller">by ${escapeHtml(p.seller)}</p> <div class="product-rating" style="margin:0.25rem 0;">${renderStars(p.rating)}<span style="font-size:0.8rem;color:var(--text-light);">(${escapeHtml(String(p.reviews))})</span> </div> <div class="product-footer"> <span class="product-price">$${p.price.toFixed(2)}</span> <button class="btn btn-primary btn-sm add-to-cart-btn" data-id="${escapeHtml(p.id)}" data-name="${escapeHtml(p.name)}" data-price="${p.price}" data-image="${escapeHtml(p.image)}"> Add to Cart </button> </div> </div> </div>`;}function renderToGrid(id,items,limit){const el=document.getElementById(id);if(!el)return;const list=limit ? items.slice(0,limit):items;el.innerHTML=list.length ? list.map(productCardHTML).join(''):'<p style="text-align:center;color:var(--text-light);padding:2rem 0;grid-column:1/-1">No products to show.</p>';}(async()=>{let products,categories;try{[products,categories]=await Promise.all([api.fetchProducts(),api.fetchCategories()]);}catch(err){console.error('Failed to load marketplace data:',err);return;}const catGrid=document.getElementById('categoryGrid');if(catGrid){catGrid.innerHTML=categories.map(c=> ` <a href="category-listing.html?cat=${escapeHtml(String(c.id).replace('cat-',''))}" class="category-card"> <div class="category-img"><img loading="lazy" src="${escapeHtml(c.image)}" alt="${escapeHtml(c.name)}"></div> <div class="category-overlay"><h3>${escapeHtml(c.name)}</h3><p>${escapeHtml(c.tagline)}</p></div> </a>`).join('');}const sellerFilter=document.getElementById('sellerFilter');if(sellerFilter){const sellers=[...new Set(products.map(p=> p.seller))];sellerFilter.innerHTML='<option value="all">All Sellers</option>'+sellers.map(s=> `<option value="${escapeHtml(s)}">${escapeHtml(s)}</option>`).join('');}renderToGrid('featuredGrid',products.filter(p=> p.featured),4);renderToGrid('bestsellerGrid',products.filter(p=> p.bestSeller),4);renderToGrid('newArrivalGrid',products.filter(p=> p.newArrival),4);const grid=document.getElementById('productGrid');const catFilter=document.getElementById('categoryFilter');const occasionFilter=document.getElementById('occasionFilter');const colorFilter=document.getElementById('colorFilter');const typeFilter=document.getElementById('typeFilter');const priceFil=document.getElementById('priceFilter');const sellerFil=document.getElementById('sellerFilter');const sortFil=document.getElementById('sortFilter');const loadMoreBtn=document.getElementById('loadMoreBtn');const pageInfo=document.getElementById('pageInfo');const productCount=document.getElementById('productCount');const heroSearch=document.getElementById('heroSearch');const activeFiltersEl=document.getElementById('activeFilters');let filtered=[...products];let shownCount=PER_PAGE;let searchQuery='';const filterLabels={category:{el:catFilter,label:'Category'},occasion:{el:occasionFilter,label:'Occasion'},color:{el:colorFilter,label:'Color'},type:{el:typeFilter,label:'Type'},price:{el:priceFil,label:'Price'},seller:{el:sellerFil,label:'Seller'}};function getActiveFilterChips(){const chips=[];if(searchQuery)chips.push({key:'search',label:`"${searchQuery}"`,clear:()=>{searchQuery='';if(heroSearch)heroSearch.value='';}});for(const [key,{el,label}] of Object.entries(filterLabels)){if(el && el.value !=='all'){const optText=el.options[el.selectedIndex]?.text || el.value;chips.push({key,label:`${label}:${optText}`,clear:()=>{el.value='all';applyFilters();}});}}return chips;}function renderActiveFilters(){if(!activeFiltersEl)return;const chips=getActiveFilterChips();activeFiltersEl.innerHTML=chips.map(c=> `<span class="filter-chip" data-key="${c.key}" style="display:inline-flex;align-items:center;gap:0.35rem;background:var(--primary-color);color:white;padding:0.3rem 0.7rem;border-radius:50px;font-size:0.8rem;font-weight:500;cursor:pointer;"> ${escapeHtml(c.label)}<i class="bi bi-x" style="font-size:0.9rem;"></i> </span>`).join('');activeFiltersEl.querySelectorAll('.filter-chip').forEach(chip=>{chip.addEventListener('click',()=>{const key=chip.dataset.key;const chipData=chips.find(c=> c.key===key);if(chipData){chipData.clear();if(key !=='search')applyFilters();else applyFilters();}});});}function applyFilters(){const q=searchQuery.toLowerCase();filtered=products.filter(p=>{if(q){const haystack=`${p.name}${p.description || ''}${p.seller}${p.category || ''}`.toLowerCase();if(!haystack.includes(q))return false;}if(catFilter?.value !=='all' && p.category !==catFilter.value)return false;if(occasionFilter?.value !=='all' && p.occasion !==occasionFilter.value)return false;if(colorFilter?.value !=='all' && p.color !==colorFilter.value)return false;if(typeFilter?.value !=='all'){if(typeFilter.value==='fresh' && !p.fresh)return false;if(typeFilter.value==='artificial' && p.fresh)return false;}if(priceFil?.value !=='all'){const v=priceFil.value;if(v.endsWith('+')){if(p.price < Number(v.slice(0,-1)))return false;}else{const [min,max]=v.split('-').map(Number);if(p.price < min || p.price > max)return false;}}if(sellerFil?.value !=='all' && p.seller !==sellerFil.value)return false;return true;});const sort=sortFil?.value;if(sort==='price-asc')filtered.sort((a,b)=> a.price-b.price);else if(sort==='price-desc')filtered.sort((a,b)=> b.price-a.price);else if(sort==='rating')filtered.sort((a,b)=> b.rating-a.rating);else if(sort==='newest')filtered.sort((a,b)=> new Date(b.createdAt || 0)-new Date(a.createdAt || 0));shownCount=PER_PAGE;renderGrid();renderActiveFilters();if(loadMoreBtn)loadMoreBtn.style.display=filtered.length > PER_PAGE ? '':'none';if(productCount)productCount.textContent=`${filtered.length}product${filtered.length !==1 ? 's':''}found`;}function renderGrid(){if(!grid)return;const items=filtered.slice(0,shownCount);if(items.length){grid.innerHTML=items.map(productCardHTML).join('');}else if(typeof EmptyState !=='undefined'){const emptyState=EmptyState.products();grid.innerHTML='';grid.appendChild(emptyState);}else{grid.innerHTML='<p style="text-align:center;color:var(--text-light);padding:3rem 0;grid-column:1/-1">No products match your filters. Try adjusting them.</p>';}if(pageInfo)pageInfo.textContent=`Showing ${Math.min(shownCount,filtered.length)}of ${filtered.length}`;if(loadMoreBtn)loadMoreBtn.style.display=shownCount >=filtered.length ? 'none':'';}document.getElementById('clearFiltersBtn')?.addEventListener('click',()=>{searchQuery='';if(heroSearch)heroSearch.value='';[catFilter,occasionFilter,colorFilter,typeFilter,priceFil,sellerFil,sortFil] .filter(Boolean).forEach(el=>{el.value=el.options[0].value;});applyFilters();});[catFilter,occasionFilter,colorFilter,typeFilter,priceFil,sellerFil,sortFil] .filter(Boolean).forEach(el=> el.addEventListener('change',applyFilters));loadMoreBtn?.addEventListener('click',()=>{shownCount+=PER_PAGE;renderGrid();});let searchTimeout;if(heroSearch){heroSearch.addEventListener('input',()=>{clearTimeout(searchTimeout);searchTimeout=setTimeout(()=>{searchQuery=heroSearch.value.trim();applyFilters();const allSection=document.getElementById('productGrid');if(allSection && searchQuery){allSection.scrollIntoView({behavior:'smooth',block:'start'});}},300);});heroSearch.addEventListener('keydown',(e)=>{if(e.key==='Enter'){e.preventDefault();clearTimeout(searchTimeout);searchQuery=heroSearch.value.trim();applyFilters();}});}applyFilters();const urlParams=new URLSearchParams(window.location.search);const catParam=urlParams.get('cat');const qParam=urlParams.get('q');if(catParam && catFilter){catFilter.value=catParam;applyFilters();}if(qParam && heroSearch){heroSearch.value=qParam;searchQuery=qParam;applyFilters();}})();document.addEventListener('click',(e)=>{const btn=e.target.closest('.wishlist-btn');if(!btn)return;const icon=btn.querySelector('i');if(icon){icon.classList.toggle('bi-heart');icon.classList.toggle('bi-heart-fill');}const id=btn.dataset.id;if(id){const saved=JSON.parse(localStorage.getItem('gallerySaved')|| '[]');const idx=saved.indexOf(id);if(idx >=0)saved.splice(idx,1);else saved.push(id);localStorage.setItem('gallerySaved',JSON.stringify(saved));}});